// Parse the HTTP response
const response = $input.first().json;

if (!response.success) {
  throw new Error(`PDF generation failed: ${response.error}\n${response.traceback || ''}`);
}

return [{
  json: {
    pdf_path: response.output_path,
    success: response.success,
    statistics: response.statistics
  }
}];

// Prepare data and send to Flask PDF server
const items = $input.all();

if (!items || items.length === 0) {
  return [];
}

// Convert to array of objects for Python script
const salesData = items.map(item => ({
  sale_number: item.json.sale_number,
  sale_status: item.json.sale_status,
  payment_method: item.json.payment_method,
  sale_total_amount: parseFloat(item.json.sale_total_amount),
  sale_time: item.json.sale_time,
  brand_name: item.json.brand_name,
  generic_name: item.json.generic_name,
  quantity: parseInt(item.json.quantity),
  unit_price: parseFloat(item.json.unit_price),
  total_price: parseFloat(item.json.total_price),
  package_description: item.json.package_description,
  quantity_on_hand: item.json.quantity_on_hand 
    ? parseInt(item.json.quantity_on_hand) 
    : 0
}));

// Get today's date for filename
const today = new Date();
const dateStr = today.toISOString().split('T')[0]; // YYYY-MM-DD

// Docker container path (was C:/Users/ismai/.n8n-files/)
const outputPath = `/home/node/.n8n-files/daily_sales_report_${dateStr}.pdf`;

return [{
  json: {
    sales_data: salesData,
    output_path: outputPath,
    report_date: dateStr,
    total_records: salesData.length
  }
}];
